event.template:
// WidgetName - Load Event Handler
// Executed when the widget is first loaded
var _this = this;

// Initialize widget
var data = _this.getData();
var options = _this.getOption();

console.log('WidgetName widget loaded', data);

// Register any custom event handlers
// Example: bpmext.ui.registerEventHandlingFunction(this, "CustomEvent", "eventName");

// Perform initial rendering or setup
// render();

// WidgetName - Change Event Handler
// Executed when the widget data changes
var _this = this;

// Get the updated data
var data = _this.getData();

console.log('WidgetName data changed:', data);

// Update the widget display based on new data
// render();

// WidgetName - View Event Handler
// Executed when the widget becomes visible
var _this = this;

// Refresh widget display
var data = _this.getData();

console.log('WidgetName widget now visible');

// Re-render or refresh the widget
// render();

// WidgetName - Validate Event Handler
// Executed during form validation
var _this = this;

// Get current data
var data = _this.getData();

// Perform validation logic
var isValid = true;
var errorMessage = "";

// Example validation
if (!data || !data.requiredField) {
    isValid = false;
    errorMessage = "Required field is missing";
}

// Return validation result
if (!isValid) {
    console.error('WidgetName validation failed:', errorMessage);
    // You can set error state on the widget
    // _this.context.element.classList.add('validation-error');
}

// Return true if valid, false if invalid
return isValid;

// WidgetName - Unload Event Handler
// Executed when the widget is being removed or destroyed
var _this = this;

console.log('WidgetName widget unloading');

// Cleanup resources
// - Remove event listeners
// - Clear timers/intervals
// - Release memory references
// - Unregister custom handlers

// Example cleanup:
// if (window.myWidgetTimer) {
